```

```java
// TEST FIRST (RED):
@Test void addItem_singleItem_totalIsItemPrice() {
    Cart cart = new Cart();
    cart.addItem("Mouse", 799.0);
    assertEquals(799.0, cart.getTotal(), 0.001);
}

// MINIMUM CODE (GREEN):
class Cart {
    private double total = 0;
    void addItem(String name, double price) { total += price; }
