```java
@Test void addTwoItems_totalIsSum() {
    Cart cart = new Cart();
    cart.addItem("Mouse", 799.0);
    cart.addItem("Keyboard", 1999.0);
    assertEquals(2798.0, cart.getTotal(), 0.001);
}
// Already GREEN — implementation works!
