```java
@Test void removeItem_existingItem_totalReduced() {
    Cart cart = new Cart();
    cart.addItem("Mouse", 799.0);
    cart.addItem("Keyboard", 1999.0);
    cart.removeItem("Mouse");
    assertEquals(1999.0, cart.getTotal(), 0.001);
}
// Implementation:
class Cart {
    private Map<String, Double> items = new LinkedHashMap<>();
    void addItem(String name, double price) { items.put(name, price); }
    void removeItem(String name)            { items.remove(name); }
    double getTotal() { return items.values().stream().mapToDouble(Double::doubleValue).sum(); }
}
// REFACTOR: changed from double total to Map<String, Double> items — clean!
```

```java
@Test void applyDiscount_10percent_reducesTotal() {
    Cart cart = new Cart();
    cart.addItem("Mouse", 799.0);
    cart.applyDiscount(0.10);
    assertEquals(719.1, cart.getTotal(), 0.001);
}
// Implementation:
void applyDiscount(double rate) {
    items.replaceAll((name, price) -> price * (1 - rate));
}
```

```java
