worked_example.final_code:
// Tests drive the design:
import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class CartTest {
    @Test void emptyCart_totalIsZero()       { assertEquals(0.0,   new Cart().getTotal(), 0.001); }
    @Test void addItem_singleItem_total()     { Cart c = new Cart(); c.addItem("Mouse",799); assertEquals(799, c.getTotal(), 0.001); }
    @Test void addTwoItems_totalIsSum()       { Cart c = new Cart(); c.addItem("Mouse",799); c.addItem("Keyboard",1999); assertEquals(2798, c.getTotal(), 0.001); }
    @Test void removeItem_existingItem_reduced() { Cart c = new Cart(); c.addItem("Mouse",799); c.addItem("Keyboard",1999); c.removeItem("Mouse"); assertEquals(1999, c.getTotal(), 0.001); }
    @Test void applyDiscount_10pct_reduced()  { Cart c = new Cart(); c.addItem("Mouse",799); c.applyDiscount(0.10); assertEquals(719.1, c.getTotal(), 0.001); }
    @Test void getItemCount_threeItems()      { Cart c = new Cart(); c.addItem("A",1); c.addItem("B",2); c.addItem("C",3); assertEquals(3, c.getItemCount()); }
}

// Production code emerged from tests:
import java.util.*;
class Cart {
    private final Map<String, Double> items = new LinkedHashMap<>();

    void addItem(String name, double price)  { items.put(name, price); }
    void removeItem(String name)             { items.remove(name); }
    void applyDiscount(double rate) {
        items.replaceAll((name, price) -> price * (1 - rate));
    }
    double getTotal()  { return items.values().stream().mapToDouble(Double::doubleValue).sum(); }
    int getItemCount() { return items.size(); }
}
